import{_ as t,o as i,c as r,ai as a,ap as l}from"./chunks/framework.JvjHW6bA.js";const _=JSON.parse('{"title":"基本 エディタ","description":"","frontmatter":{},"headers":[],"relativePath":"usage/ui/basic_editor.md","filePath":"usage/ui/basic_editor.md"}'),h={name:"usage/ui/basic_editor.md"};function s(c,e,o,d,n,x){return i(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="基本-エディタ" tabindex="-1">基本 エディタ <a class="header-anchor" href="#基本-エディタ" aria-label="Permalink to “基本 エディタ”">​</a></h1><p><img src="'+l+'" alt="alt text"></p><h2 id="各項目の詳細" tabindex="-1">各項目の詳細 <a class="header-anchor" href="#各項目の詳細" aria-label="Permalink to “各項目の詳細”">​</a></h2><p>選択中のキューについて、情報や設定を変更することができます。<br> （選択中のキューであり、カーソルとは関係ありません。）</p><h3 id="_1-キュー番号" tabindex="-1"><svg viewBox="0 0 26 26" width="25" height="25"><circle cx="13" cy="13" r="12" stroke="white" stroke-width="2px" fill="red"></circle><text x="13" y="21" text-anchor="middle" fill="white" font-size="16pt">1</text></svg> キュー番号 <a class="header-anchor" href="#_1-キュー番号" aria-label="Permalink to “1 キュー番号”">​</a></h3><p>キューに設定される番号を編集します。</p><p><strong>再生される順序とは関係ありません。</strong><br> 数値だけでなく、文字列も使用することができます。</p><h3 id="_2-キューの名前" tabindex="-1"><svg viewBox="0 0 26 26" width="25" height="25"><circle cx="13" cy="13" r="12" stroke="white" stroke-width="2px" fill="red"></circle><text x="13" y="21" text-anchor="middle" fill="white" font-size="16pt">2</text></svg> キューの名前 <a class="header-anchor" href="#_2-キューの名前" aria-label="Permalink to “2 キューの名前”">​</a></h3><p>キューに設定される名称を編集します。<br> 空欄にすることで、キューの種類や設定に応じて自動的に名称が設定されます。</p><h3 id="_3-キューのノート" tabindex="-1"><svg viewBox="0 0 26 26" width="25" height="25"><circle cx="13" cy="13" r="12" stroke="white" stroke-width="2px" fill="red"></circle><text x="13" y="21" text-anchor="middle" fill="white" font-size="16pt">3</text></svg> キューのノート <a class="header-anchor" href="#_3-キューのノート" aria-label="Permalink to “3 キューのノート”">​</a></h3><p>キューに設定されるノートを編集します。<br> 上部ヘッダーに表示されるため、タイミング等の情報を記入できます。<br><a href="#_8-ノートへのタイムスタンプ挿入ボタン">タイムスタンプ挿入ボタン</a>を利用することでキューのタイムスタンプを記録できます。</p><h3 id="_4-キューの長さ" tabindex="-1"><svg viewBox="0 0 26 26" width="25" height="25"><circle cx="13" cy="13" r="12" stroke="white" stroke-width="2px" fill="red"></circle><text x="13" y="21" text-anchor="middle" fill="white" font-size="16pt">4</text></svg> キューの長さ <a class="header-anchor" href="#_4-キューの長さ" aria-label="Permalink to “4 キューの長さ”">​</a></h3><p>音声キューの場合はファイルの音声の長さが表示され編集はできません。<br> 待機キューの場合は待機時間を、フェードキューの場合はフェードにかける時間を編集することができます。</p><h4 id="_5-キューの事前待機時間" tabindex="-1"><svg viewBox="0 0 26 26" width="25" height="25"><circle cx="13" cy="13" r="12" stroke="white" stroke-width="2px" fill="red"></circle><text x="13" y="21" text-anchor="middle" fill="white" font-size="16pt">5</text></svg> キューの事前待機時間 <a class="header-anchor" href="#_5-キューの事前待機時間" aria-label="Permalink to “5 キューの事前待機時間”">​</a></h4><p>キュー実行前の待機時間を編集できます。</p><h4 id="_6-キューの連鎖モード" tabindex="-1"><svg viewBox="0 0 26 26" width="25" height="25"><circle cx="13" cy="13" r="12" stroke="white" stroke-width="2px" fill="red"></circle><text x="13" y="21" text-anchor="middle" fill="white" font-size="16pt">6</text></svg> キューの連鎖モード <a class="header-anchor" href="#_6-キューの連鎖モード" aria-label="Permalink to “6 キューの連鎖モード”">​</a></h4><p>キューの連鎖モードを編集できます。</p><ul><li><strong>連鎖しない</strong>：キュー終了後に何も行いません</li><li><strong>開始後</strong>：キュー開始後に対象のキューを実行します。</li><li><strong>終了後</strong>：キュー終了後に対象のキューを実行します。</li></ul><h4 id="_7-キュー連鎖の対象" tabindex="-1"><svg viewBox="0 0 26 26" width="25" height="25"><circle cx="13" cy="13" r="12" stroke="white" stroke-width="2px" fill="red"></circle><text x="13" y="21" text-anchor="middle" fill="white" font-size="16pt">7</text></svg> キュー連鎖の対象 <a class="header-anchor" href="#_7-キュー連鎖の対象" aria-label="Permalink to “7 キュー連鎖の対象”">​</a></h4><p>キューの連鎖モードが設定されている時、連鎖する対象のキューを編集できます。<br> デフォルトではキューリストの次のキューが対象となっています。</p><h4 id="_8-ノートへのタイムスタンプ挿入ボタン" tabindex="-1"><svg viewBox="0 0 26 26" width="25" height="25"><circle cx="13" cy="13" r="12" stroke="white" stroke-width="2px" fill="red"></circle><text x="13" y="21" text-anchor="middle" fill="white" font-size="16pt">8</text></svg> ノートへのタイムスタンプ挿入ボタン <a class="header-anchor" href="#_8-ノートへのタイムスタンプ挿入ボタン" aria-label="Permalink to “8 ノートへのタイムスタンプ挿入ボタン”">​</a></h4><p>キューが実行中の時、現在の経過時間をノートの挿入します。<br> タイミングをノートに記入する際に便利です。</p>',22)])])}const f=t(h,[["render",s]]);export{_ as __pageData,f as default};
